package main

import (
	"fmt"
	"net/http"
	"os"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

// Define a new Prometheus metric with labels for user and request type.
var (
	userRequestCounter = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_requests_total",
			Help: "Total number of requests per user and request type.",
		},
		[]string{"user", "request_type"},
	)
)

func init() {
	// Register the metric with Prometheus.
	prometheus.MustRegister(userRequestCounter)
}

func handleRequests(w http.ResponseWriter, r *http.Request) {
	// Extract user and request type from query parameters.
	user := r.URL.Query().Get("user")
	requestType := r.URL.Query().Get("request_type")

	if user == "" || requestType == "" {
		http.Error(w, "Missing 'user' or 'request_type' parameter", http.StatusBadRequest)
		return
	}

	// Increment the counter for the given user and request type.
	userRequestCounter.WithLabelValues(user, requestType).Inc()

	fmt.Fprintf(w, "Request recorded for user %s with type %s\n", user, requestType)
}

func main() {
	http.HandleFunc("/metrics", promhttp.Handler().ServeHTTP)
	http.HandleFunc("/record", handleRequests)

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	fmt.Printf("Starting server on :%s\n", port)
	if err := http.ListenAndServe(":"+port, nil); err != nil {
		fmt.Println("Error starting server:", err)
	}
}